sealed class Expr {
    data class Num(val value: Int) : Expr()
    data class Sum(val left: Expr, val right: Expr) : Expr()
    data class Mul(val left: Expr, val right: Expr) : Expr()
}

fun evaluate(expr: Expr): Int = when (expr) {
    is Expr.Num -> expr.value
    is Expr.Sum -> evaluate(expr.left) + evaluate(expr.right)
    is Expr.Mul -> evaluate(expr.left) * evaluate(expr.right)
}

fun main() {
    val expr = Expr.Sum(Expr.Num(3), Expr.Mul(Expr.Num(4), Expr.Num(2)))
    println(evaluate(expr))  // 3 + (4 * 2) = 11
}
